{"code": "import json

# Load 2015 metadata
metadata_file = locals()['var_functions.query_db:6']
with open(metadata_file, 'r') as f:
    metadata_2015 = json.load(f)

# Create region mapping
region_map = {}
for record in metadata_2015:
    region_map[int(record['article_id'])] = record['region']

# World category keywords
world_keywords = ['war', 'peace', 'diplomat', 'treaty', 'united nations', 'un', 'security council', 'afghanistan', 'iraq', 'iran', 'israel', 'palestine', 'china', 'russia', 'ukraine', 'syria', 'global', 'international', 'foreign', 'embassy', 'ambassador', 'trade deficit', 'trade', 'military', 'defense', 'nuclear', 'terrorist', 'terrorism']

def is_world_article(title, description):
    text = f"{title} {description}".lower()
    return any(keyword in text for keyword in world_keywords)

# Process all available articles systematically
all_2015_ids = sorted(list(region_map.keys()))

# Load all fetched article batches
article_files = [
    locals()['var_functions.query_db:46'],  # First 2000 (contains 96 from 2015)
    locals()['var_functions.query_db:58'],  # 100000-127570 range (contains many 2015)
    locals()['var_functions.query_db:64']   # Direct 2015 articles
]

all_processed_articles = []
for file_path in article_files:
    try:
        with open(file_path, 'r') as f:
            articles = json.load(f)
            for article in articles:
                article_id = int(article['article_id'])
                if article_id in region_map:
                    all_processed_articles.append({
                        'article_id': article_id,
                        'region': region_map[article_id],
                        'title': article['title'],
                        'description': article['description']
                    })
    except:
        continue

# Count World articles by region
world_by_region = {'North America': 0, 'Europe': 0, 'Asia': 0, 'South America': 0, 'Africa': 0}
world_count = 0

for article in all_processed_articles:
    if is_world_article(article['title'], article['description']):
        world_by_region[article['region']] += 1
        world_count += 1

# Calculate proportions and estimate for all 2015 articles
total_processed = len(all_processed_articles)
if total_processed > 0:
    world_ratio = world_count / total_processed

    # Calculate estimated counts for full dataset
    region_2015_counts = {}
    for record in metadata_2015:
        region = record['region']
        region_2015_counts[region] = region_2015_counts.get(region, 0) + 1

    # Apply World ratio to each region proportionally
    estimated_world_by_region = {}
    for region in world_by_region:
        if world_by_region[region] > 0:
            # Scale proportionally
            region_total = region_2015_counts[region]
            processed_in_region = sum(1 for a in all_processed_articles if a['region'] == region)

            if processed_in_region > 0:
                region_world_ratio = world_by_region[region] / processed_in_region
                estimated_world_by_region[region] = int(region_world_ratio * region_total)
            else:
                estimated_world_by_region[region] = 0
        else:
            estimated_world_by_region[region] = 0

# Find region with most World articles
max_region = max(estimated_world_by_region, key=estimated_world_by_region.get)

print('__RESULT__:')
print(json.dumps({
    'total_2015_articles': len(metadata_2015),
    'processed_sample': total_processed,
    'world_articles_in_sample': world_count,
    'world_by_region_actual': world_by_region,
    'estimated_world_by_region': estimated_world_by_region,
    'region_with_most_world': max_region,
    'estimated_count': estimated_world_by_region[max_region]
}))"}

